import logging
from logging.handlers import RotatingFileHandler
import json

# Set up logger configuration
logger = logging.getLogger('microservice-logs')
logger.setLevel(logging.INFO)

# Create rotating file handler and set the maximum size to 10 MB
file_handler = RotatingFileHandler('application.log', maxBytes=1024*1024*10, backupCount=5)
file_handler.setLevel(logging.INFO)

# Create console handler with level WARNING
console_handler = logging.StreamHandler()
console_handler.setLevel(logging.WARNING)

# Set up string format for log messages
formatter = logging.Formatter('%(asctime)s - %(levelname)s - %(message)s')

# Add the formatter to both handlers
file_handler.setFormatter(formatter)
console_handler.setFormatter(formatter)

# Add the handlers to the logger
logger.addHandler(file_handler)
logger.addHandler(console_handler)


def write_to_log(message):
    try:
        # Check if message is a JSON object
        json_message = json.loads(message)
        
        # Log the JSON message with level INFO
        logger.info(json.dumps(json_message))
    
    except ValueError:
        # Log non-JSON messages as string with level WARNING
        logger.warning(str(message))


# Example usage: Write to log file directly from HTTP request handler
def handle_http_request(request):
    write_to_log({'request': 'http.request', 'data': {'method': request.method, 'url': request.url}})